struct bstorm_dispatch_config {
    enum bstorm_engine_control bstm;
    std::string graph_path;
    std::string hw_remote;
    bool direct_access = true;
};

class bstorm_device_context {
  public:
    bstorm_device_context()
    {
        config_.bstm = bstorm_engine_default;
    }

    ~bstorm_device_context()
    {
        if (bstorm_context_) {
            bstorm_context_destroy(bstorm_context_);
        }
    }

    bstorm_result init()
    {
        bstorm_result rc = BSTORM_RESULT_INITIALIZER();
        struct bstorm_context_config context_config;
        struct bstorm_context_status status;
        const char* options_env = std::getenv("BSTORM_DISPATCH_OPTIONS");

        bstorm_context_config_Default(&context_config);
        if (options_env != nullptr) {
            B_STORM_DEBUG("BSTORM_DISPATCH_OPTIONS: %s", options_env);
            std::string options_str(options_env);
            B_STORM_CHECKED_CALL(rc, parse_options, (options_str), err_parse_options);
        }
        if (!config_.hw_remote.empty()) {
            context_config.bstm.hw_config.remote.server = config_.hw_remote.c_str();
            B_STORM_DEBUG("Using remote BSTM hardware: %s", config_.hw_remote.c_str());
        }
        if (config_.bstm == bstorm_engine_disable) {
            context_config.engine.allow.bstm = false;
        } else if (config_.bstm == bstorm_engine_enable) {
            context_config.engine.allow.bstm = true;
        }
        B_STORM_CHECKED_NULL_CALL(rc, bstorm_context_, bstorm_context_create, (&context_config), err_context);
        B_STORM_CHECKED_CALL(rc, bstorm_context_get_status, (bstorm_context_, &status), err_status);
        if (config_.bstm == bstorm_engine_enable) {
            B_STORM_CONDITION(rc, status.engine.bstm.enabled, err_engine);
        }

        return rc;

    err_engine:
    err_status:
        bstorm_context_destroy(bstorm_context_);
        bstorm_context_ = nullptr;
    err_context:
    err_parse_options:
        return rc;
    }

    struct bstorm_context *get_bstorm_context() const
    {
        B_STORM_ASSERT(bstorm_context_);
        return bstorm_context_;
    }

    const bstorm_dispatch_config& get_config() const
    {
        return config_;
    }

    bstorm_result register_buffer(LiteRtTensorBuffer buffer, void** handle)
    {
        bstorm_result rc = BSTORM_RESULT_INITIALIZER();
        *handle = static_cast<void*>(buffer);
        buffer_map_[*handle] = buffer;
        return rc;
    }

    bstorm_result unregister_buffer(void* handle)
    {
        bstorm_result rc = BSTORM_RESULT_INITIALIZER();
        buffer_map_.erase(handle);
        return rc;
    }

    LiteRtTensorBuffer lookup_buffer(void* handle)
    {
        auto it = buffer_map_.find(handle);
        if (it != buffer_map_.end()) {
            return it->second;
        }
        return nullptr;
    }

  private:
    bstorm_result parse_options(const std::string& options_str)
    {
        bstorm_result rc = BSTORM_RESULT_INITIALIZER();
        size_t pos = 0;
        std::string token;
        std::string options = options_str;

        while ((pos = options.find(',')) != std::string::npos) {
            token = options.substr(0, pos);
            B_STORM_CHECKED_CALL(rc, parse_option_pair, (token), err_parse_option_pair);
            options.erase(0, pos + 1);
        }
        // Parse the last token (or the only token if no comma was found)
        if (!options.empty()) {
            B_STORM_CHECKED_CALL(rc, parse_option_pair, (options), err_parse_option_pair);
        }
        return rc;
    err_parse_option_pair:
        return rc;
    }

    bstorm_result parse_option_pair(const std::string& option)
    {
        bstorm_result rc = BSTORM_RESULT_INITIALIZER();
        size_t eq_pos = option.find('=');
        if (eq_pos != std::string::npos) {
            std::string key = option.substr(0, eq_pos);
            std::string value = option.substr(eq_pos + 1);
            const char* cvalue = value.c_str();

            if (key == "graph-path") {
                config_.graph_path = value;
            } else if (key == "bstm") {
                config_.bstm = bstorm_engine_control_from_arg(cvalue);
            } else if (key == "direct-access") {
                config_.direct_access = atoi(cvalue);
            } else if (key == "bstm-hw-remote") {
                config_.hw_remote = value;
                auto slash = config_.hw_remote.rfind('/');
                if (slash != std::string::npos) {
                    config_.hw_remote[slash] = ':';
                }
            } else {
                B_STORM_ERROR(rc, NotSupported, err_invalid_option);
            }
        }
        return rc;
    err_invalid_option:
        return rc;
    }

    struct bstorm_context *bstorm_context_ = nullptr;
    std::map<void*, LiteRtTensorBuffer> buffer_map_;
    bstorm_dispatch_config config_;
};

