// Graph Class Implementation
//==============================================================================

class bstorm_dispatch_graph {
    public:
      bstorm_dispatch_graph(bstorm_device_context* device_context)
          : device_context_(device_context)
      {
          memset(&flatbuf_, 0, sizeof(flatbuf_));
          memset(&graph_state_, 0, sizeof(graph_state_));
      }

      ~bstorm_dispatch_graph()
      {
          unprepare_graph();
          unload_graph();
      }

      bstorm_result load_graph(const std::string& graph_name, const std::string& graph_path, unsigned& num_inputs)
      {
          bstorm_result rc = BSTORM_RESULT_INITIALIZER();
          struct bstorm_Graph_Info info;
          std::string resolved_graph_path = graph_name;

          B_STORM_PRECONDITION(rc, !graph_loaded_, err_loaded);
          if (!graph_path.empty()) {
              resolved_graph_path = graph_path + "/" + graph_name;
          }
          B_STORM_DEBUG("Using bstorm graph: %s", resolved_graph_path.c_str());
          B_STORM_CHECKED_CALL(rc, bstorm_flatbuf_read, (resolved_graph_path.c_str(), &flatbuf_, nullptr), err_read);
          B_STORM_ASSERT(flatbuf_.graph != NULL);
          B_STORM_ASSERT(flatbuf_.graph->graph != NULL);
          bstorm_graph_ = flatbuf_.graph->graph;
          graph_loaded_ = true;

          bstorm_Graph_GetInfo(bstorm_graph_, &info);
          B_STORM_DEBUG("Loaded graph: nodes=%u, blobs=%u, inputs=%u, outputs=%u",
                        info.nodes, info.blobs, info.inputs, info.outputs);
          num_inputs = info.inputs;
          return rc;

      err_read:
      err_loaded:
          return rc;
      }

      void unload_graph()
      {
          if (graph_loaded_) {
              bstorm_flatbuf_free(&flatbuf_);
              graph_loaded_ = false;
              bstorm_graph_ = NULL;
          }
      }

      bstorm_result prepare_graph(struct bstorm_Blobs& output_blobs)
      {
          bstorm_result rc = BSTORM_RESULT_INITIALIZER();

          B_STORM_PRECONDITION(rc, graph_loaded_, err_loaded);
          B_STORM_PRECONDITION(rc, !graph_prepared_, err_prepared);
          B_STORM_CHECKED_CALL(rc, bstorm_Graph_Prepare, (device_context_->get_bstorm_context(), bstorm_graph_, &graph_state_, &output_blobs), err_prepare);
          graph_prepared_ = true;
          return rc;

      err_prepare:
      err_prepared:
      err_loaded:
          return rc;
      }

      void unprepare_graph()
      {
          if (graph_prepared_) {
              bstorm_Graph_Unprepare(&graph_state_);
              graph_prepared_ = false;
          }
      }

      bstorm_result execute_graph(struct bstorm_Blobs& input_blobs, struct bstorm_Blobs& output_blobs)
      {
          bstorm_result rc = BSTORM_RESULT_INITIALIZER();

          B_STORM_PRECONDITION(rc, graph_prepared_, err_not_prepared);
          B_STORM_CHECKED_CALL(rc, bstorm_Graph_Execute, (&graph_state_, &input_blobs, &output_blobs), err_execute);
          return rc;

      err_execute:
      err_not_prepared:
          return rc;
      }

      bstorm_result copy_shape(unsigned blob_index, struct bstorm_Blob& blob, bool is_input)
      {
          bstorm_result rc = BSTORM_RESULT_INITIALIZER();
          const struct bstorm_GraphInfo *graph_info;
          const struct bstorm_Blobs *graph_blobs;
          const struct bstorm_Blob *graph_blob;

          B_STORM_PRECONDITION(rc, graph_loaded_, err_not_loaded);
          bstorm_Graph_GetGraphInfo(bstorm_graph_, &graph_info);
          B_STORM_ASSERT(graph_info != NULL);
          graph_blobs = (is_input) ? &graph_info->inputs : &graph_info->outputs;
          B_STORM_CHECKED_NULL_CALL(rc, graph_blob, bstorm_Blobs_GetBlob, (graph_blobs, blob_index), err_copy);
          B_STORM_CHECKED_CALL(rc, bstorm_BlobShape_Copy, (&blob.shape, &graph_blob->shape), err_copy);
          return rc;

      err_copy:
      err_not_loaded:
          return rc;
      }

  private:
    bool graph_loaded_ = false;
    bool graph_prepared_ = false;
    struct bstorm_Graph* bstorm_graph_ = NULL;
    struct bstorm_flatbuf flatbuf_;
    struct bstorm_GraphState graph_state_;
    bstorm_device_context* device_context_;
};

//==============================================================================
// Precompiled Graph Class Implementation
// Loads .bstm files and executes via bstorm_bstm_precompiled_exec()
//==============================================================================

class bstorm_dispatch_precompiled_graph {
    public:
      bstorm_dispatch_precompiled_graph(bstorm_device_context* device_context)
          : device_context_(device_context)
      {
      }

      ~bstorm_dispatch_precompiled_graph()
      {
          unload_model();
      }

      bstorm_result load_model_from_file(const std::string& bstm_path, const std::string& graph_path, unsigned& num_inputs)
      {
          bstorm_result rc = BSTORM_RESULT_INITIALIZER();
          struct bstorm_bstm_precompiled_model_config config;
          std::string resolved_path = bstm_path;

          B_STORM_PRECONDITION(rc, !model_loaded_, err_loaded);
          if (!graph_path.empty()) {
              resolved_path = graph_path + "/" + bstm_path;
          }
          B_STORM_DEBUG("Loading precompiled .bstm from file: %s", resolved_path.c_str());
          init_load_config(config);
          precompiled_model_ = bstorm_bstm_precompiled_model_load(
              device_context_->get_bstorm_context(), resolved_path.c_str(), &config);
          return finish_load(num_inputs);

      err_loaded:
          return rc;
      }

      bstorm_result load_model_from_buffer(const struct bstorm_compiler_bstm_offline_output_buffer& buffer, unsigned& num_inputs)
      {
          bstorm_result rc = BSTORM_RESULT_INITIALIZER();
          struct bstorm_bstm_precompiled_model_config config;

          B_STORM_PRECONDITION(rc, !model_loaded_, err_loaded);
          B_STORM_DEBUG("Loading precompiled .bstm from buffer (%zu bytes)", buffer.buffer_size);
          init_load_config(config);
          precompiled_model_ = bstorm_bstm_precompiled_model_load_from_buffer(
              device_context_->get_bstorm_context(), &buffer, &config);
          return finish_load(num_inputs);

      err_loaded:
          return rc;
      }

      void unload_model()
      {
          if (model_loaded_) {
              bstorm_bstm_precompiled_model_release(precompiled_model_);
              precompiled_model_ = NULL;
              model_loaded_ = false;
          }
      }

      bstorm_result execute(struct bstorm_Blobs& input_blobs, struct bstorm_Blobs& output_blobs)
      {
          bstorm_result rc = BSTORM_RESULT_INITIALIZER();
          struct bstorm_bstm_PrecompiledExecuteStats stats;
          unsigned i;

          B_STORM_PRECONDITION(rc, model_loaded_, err_not_loaded);
          for (i = 0; i < input_blobs.count; i++) {
              const struct bstorm_Blob* blob = bstorm_Blobs_GetBlob(&input_blobs, i);
              if (blob && blob->data) {
                  B_STORM_CHECKED_CALL(rc, bstorm_bstm_precompiled_write_input,
                      (precompiled_model_, i, blob->data, bstorm_BlobShape_Size(&blob->shape)), err_write);
              }
          }
          memset(&stats, 0, sizeof(stats));
          B_STORM_CHECKED_CALL(rc, bstorm_bstm_precompiled_exec,
              (device_context_->get_bstorm_context(), precompiled_model_, &stats), err_exec);
          B_STORM_DEBUG("Precompiled exec: cpu_time=%u us, cycles=%u", stats.cpu_time, stats.cycles);
          for (i = 0; i < output_blobs.count; i++) {
              const struct bstorm_Blob* blob = bstorm_Blobs_GetBlob(&output_blobs, i);
              if (blob && blob->data) {
                  B_STORM_CHECKED_CALL(rc, bstorm_bstm_precompiled_read_output,
                      (precompiled_model_, i, blob->data, bstorm_BlobShape_Size(&blob->shape)), err_read);
              }
          }
          return rc;

      err_read:
      err_exec:
      err_write:
      err_not_loaded:
          return rc;
      }

      unsigned get_num_outputs() const { return num_outputs_; }

  private:
    void init_load_config(struct bstorm_bstm_precompiled_model_config& config)
    {
        direct_access_ = device_context_->get_config().hw_remote.empty()
                         && device_context_->get_config().direct_access;
        bstorm_bstm_precompiled_model_config_default(&config);
        if (direct_access_) {
            config.payload_access = bstorm_bstm_payload_access_direct;
        }
    }

    bstorm_result finish_load(unsigned& num_inputs)
    {
        bstorm_result rc = BSTORM_RESULT_INITIALIZER();
        struct bstorm_bstm_precompiled_model_info info;

        if (!precompiled_model_) {
            B_STORM_ERROR(rc, Unknown, err_load);
        }
        B_STORM_CHECKED_CALL(rc, bstorm_bstm_precompiled_get_model_info, (precompiled_model_, &info), err_info);
        num_inputs = info.input.count;
        num_outputs_ = info.output.count;
        model_loaded_ = true;
        B_STORM_DEBUG("Loaded precompiled model: inputs=%u, outputs=%u, size=%u",
                      num_inputs, num_outputs_, info.size);
        return rc;

    err_info:
        bstorm_bstm_precompiled_model_release(precompiled_model_);
        precompiled_model_ = NULL;
    err_load:
        return rc;
    }

    bool model_loaded_ = false;
    bool direct_access_ = false;
    unsigned num_outputs_ = 0;
    struct bstorm_bstm_precompiled_model* precompiled_model_ = NULL;
    bstorm_device_context* device_context_;
};

//==============================================================================
// Invocation Context Class Implementation
//==============================================================================

class bstorm_invocation_context {
  public:
    bstorm_invocation_context() {}

    ~bstorm_invocation_context()
    {
        if (input_blobs_allocated_) {
            bstorm_Blobs_Clear(&input_blobs_);
            bstorm_Blobs_Uninit(&input_blobs_);
        }
        if (output_blobs_allocated_) {
            bstorm_Blobs_Clear(&output_blobs_);
            bstorm_Blobs_Uninit(&output_blobs_);
        }
    }

    bstorm_result init(
        bstorm_device_context* device_context,
        LiteRtDispatchExecutableType exec_type,
        const LiteRtMemBuffer* mem_buffer,
        const char* function_name,
        unsigned num_inputs,
        unsigned num_outputs)
    {
        bstorm_result rc = BSTORM_RESULT_INITIALIZER();
        std::string function_name_str(function_name);
        unsigned i;

        B_STORM_PRECONDITION(rc, device_context_ == NULL, err_init);
        if (!device_context || !mem_buffer || !function_name) {
            B_STORM_ERROR(rc, InvalidParameter, err_invalid_args);
        }
        device_context_ = device_context;

        bstorm_Blobs_Init(&input_blobs_);
        B_STORM_CHECKED_CALL(rc, bstorm_Blobs_AllocateBlobs, (&input_blobs_, num_inputs), err_input_blobs);
        input_blobs_allocated_ = true;
        for (i = 0; i < num_inputs; i++) {
            B_STORM_CHECKED_CALL(rc, bstorm_Blobs_UseInlineBlob, (&input_blobs_, i), err_input_blobs);
        }

        bstorm_Blobs_Init(&output_blobs_);
        B_STORM_CHECKED_CALL(rc, bstorm_Blobs_AllocateBlobs, (&output_blobs_, num_outputs), err_output_blobs);
        output_blobs_allocated_ = true;
        for (i = 0; i < num_outputs; i++) {
            B_STORM_CHECKED_CALL(rc, bstorm_Blobs_UseInlineBlob, (&output_blobs_, i), err_output_blobs);
        }

        {
            unsigned graph_num_inputs;
            const uint8_t* data = static_cast<const uint8_t*>(mem_buffer->base_addr);

            if (function_name_str == "bstm.embedded") {
                struct bstorm_compiler_bstm_offline_output_buffer bstm_buf = {(void*)(data + mem_buffer->offset), mem_buffer->size};

                B_STORM_DEBUG("Dispatch: function_name='%s' buffer_size=%zu", function_name, bstm_buf.buffer_size);
                precompiled_graph_ = std::make_unique<bstorm_dispatch_precompiled_graph>(device_context_);
                B_STORM_ASSERT(precompiled_graph_);
                B_STORM_CHECKED_CALL(rc, precompiled_graph_->load_model_from_buffer, (bstm_buf, graph_num_inputs), err_load_precompiled);
                B_STORM_ASSERT(graph_num_inputs == num_inputs);
                B_STORM_ASSERT(precompiled_graph_->get_num_outputs() == num_outputs);
            } else {
                std::string file_name(reinterpret_cast<const char*>(data + mem_buffer->offset), mem_buffer->size);
                const std::string& graph_path = device_context_->get_config().graph_path;

                B_STORM_DEBUG("Dispatch: function_name='%s' file='%s'", function_name, file_name.c_str());
                if (function_name_str == "bstm") {
                    precompiled_graph_ = std::make_unique<bstorm_dispatch_precompiled_graph>(device_context_);
                    B_STORM_ASSERT(precompiled_graph_);
                    B_STORM_CHECKED_CALL(rc, precompiled_graph_->load_model_from_file, (file_name, graph_path, graph_num_inputs), err_load_precompiled);
                    B_STORM_ASSERT(graph_num_inputs == num_inputs);
                    B_STORM_ASSERT(precompiled_graph_->get_num_outputs() == num_outputs);
                } else {
                    dispatch_graph_ = std::make_unique<bstorm_dispatch_graph>(device_context_);
                    B_STORM_ASSERT(dispatch_graph_);
                    B_STORM_DEBUG("Loading graph from file: %s", file_name.c_str());
                    B_STORM_CHECKED_CALL(rc, dispatch_graph_->load_graph, (file_name, graph_path, graph_num_inputs), err_load_graph);
                    B_STORM_ASSERT(graph_num_inputs == num_inputs);
                    B_STORM_CHECKED_CALL(rc, dispatch_graph_->prepare_graph, (output_blobs_), err_prepare);
                    B_STORM_ASSERT(output_blobs_.count == num_outputs);
                }
            }
        }
        return rc;

    err_load_precompiled:
        if (precompiled_graph_) {
            precompiled_graph_->unload_model();
        }
    err_prepare:
        if (dispatch_graph_) {
            dispatch_graph_->unload_graph();
        }
    err_load_graph:
    err_output_blobs:
        bstorm_Blobs_Clear(&output_blobs_);
        bstorm_Blobs_Uninit(&output_blobs_);
        output_blobs_allocated_ = false;
    err_input_blobs:
        bstorm_Blobs_Clear(&input_blobs_);
        bstorm_Blobs_Uninit(&input_blobs_);
        input_blobs_allocated_ = false;
        device_context_ = NULL;
    err_invalid_args:
    err_init:
        return rc;
    }

    bstorm_result attach_input(unsigned graph_input_index, void* handle)
    {
        return attach_blob(graph_input_index, handle, input_blobs_, true);
    }

    bstorm_result attach_output(unsigned graph_output_index, void* handle)
    {
        return attach_blob(graph_output_index, handle, output_blobs_, false);
    }

    bstorm_result detach_input(unsigned graph_input_index, void* handle)
    {
        return detach_blob(graph_input_index, handle, input_blobs_);
    }

    bstorm_result detach_output(unsigned graph_output_index, void* handle)
    {
        return detach_blob(graph_output_index, handle, output_blobs_);
    }

    bstorm_result invoke()
    {
        bstorm_result rc = BSTORM_RESULT_INITIALIZER();
        if (precompiled_graph_) {
            B_STORM_CHECKED_CALL(rc, precompiled_graph_->execute, (input_blobs_, output_blobs_), err_execute);
        } else {
            B_STORM_ASSERT(dispatch_graph_);
            B_STORM_CHECKED_CALL(rc, dispatch_graph_->execute_graph, (input_blobs_, output_blobs_), err_execute);
        }
        return rc;

    err_execute:
        return rc;
    }

    bstorm_result get_graph(LiteRtDispatchGraph* graph) {
        bstorm_result rc = BSTORM_RESULT_INITIALIZER();

        B_STORM_CONDITION(rc, dispatch_graph_, err_graph);
        B_STORM_ASSERT(graph);
        *graph = reinterpret_cast<LiteRtDispatchGraph>(dispatch_graph_.get());
        return rc;

    err_graph:
        *graph = nullptr;
        return rc;
    }

  private:
    bstorm_result attach_blob(unsigned index, void* handle, struct bstorm_Blobs& blobs, bool is_input)
    {
        bstorm_result rc = BSTORM_RESULT_INITIALIZER();
        LiteRtTensorBuffer tensor_buffer;
        struct bstorm_Blob* blob;

        B_STORM_PRECONDITION(rc, index < blobs.count, err_invalid_index);
        B_STORM_CHECKED_NULL_CALL(rc, tensor_buffer, device_context_->lookup_buffer, (handle), err_invalid_buffer);
        blob = blobs.entry[index];
        B_STORM_CHECKED_CALL(rc, bstorm_LiteRt_BlobFromTensorBuffer, (blob, tensor_buffer), err_blob);

        // If dispatch_graph_ is available, copy the blob shape and quantization parameters from the graph.
        // This is necessary because the quantization parameters are not available in the tensor_buffer.
        if (dispatch_graph_ != NULL) {
            B_STORM_CHECKED_CALL(rc, dispatch_graph_->copy_shape, (index, *blob, is_input), err_copy_shape);
        }

        return rc;

    err_copy_shape:
    err_blob:
    err_invalid_buffer:
    err_invalid_index:
        return rc;
    }

    static bstorm_result detach_blob(unsigned index, void* handle, struct bstorm_Blobs& blobs)
    {
        bstorm_result rc = BSTORM_RESULT_INITIALIZER();
        struct bstorm_Blob* blob;

        B_STORM_PRECONDITION(rc, index < blobs.count, err_invalid_index);
        blob = blobs.entry[index];
        bstorm_Blob_Default(blob);
        return rc;

    err_invalid_index:
        return rc;
    }

    bstorm_device_context* device_context_ = NULL;
    bool input_blobs_allocated_ = false;
    bool output_blobs_allocated_ = false;
    struct bstorm_Blobs input_blobs_;
    struct bstorm_Blobs output_blobs_;
    std::unique_ptr<bstorm_dispatch_graph> dispatch_graph_;
    std::unique_ptr<bstorm_dispatch_precompiled_graph> precompiled_graph_;
};

