static LiteRtStatus bstorm_LiteRt_get_tensor_buffer_requirements(
    const LiteRtRankedTensorType& tensor_type,
    LiteRtTensorBufferRequirements* tensor_buffer_requirements)
{
    litert::RankedTensorType t(tensor_type);
    static constexpr LiteRtTensorBufferType types[] = {
        kLiteRtTensorBufferTypeHostMemory
    };
    auto size_result = t.Bytes();
    if (!size_result) {
        return kLiteRtStatusErrorRuntimeFailure;
    }
    return LiteRtCreateTensorBufferRequirements(
        1, types, *size_result, 0, nullptr, tensor_buffer_requirements);
}

static LiteRtStatus bstorm_LiteRt_get_input_requirements(
    LiteRtDispatchInvocationContext invocation_context, int input_index,
    const LiteRtRankedTensorType* tensor_type,
    LiteRtTensorBufferRequirements* tensor_buffer_requirements)
{
    return bstorm_LiteRt_get_tensor_buffer_requirements(*tensor_type, tensor_buffer_requirements);
}

static LiteRtStatus bstorm_LiteRt_get_output_requirements(
    LiteRtDispatchInvocationContext invocation_context, int output_index,
    const LiteRtRankedTensorType* tensor_type,
    LiteRtTensorBufferRequirements* tensor_buffer_requirements)
{
    return bstorm_LiteRt_get_tensor_buffer_requirements(*tensor_type, tensor_buffer_requirements);
}

static LiteRtStatus bstorm_LiteRt_register_tensor_buffer(
    LiteRtDispatchDeviceContext device_context, LiteRtTensorBuffer buffer,
    LiteRtTensorBufferHandle* tensor_buffer_handle)
{
    bstorm_result rc = BSTORM_RESULT_INITIALIZER();
    void* handle = nullptr;
    B_STORM_CHECKED_CALL(rc, device_context->register_buffer, (buffer, &handle), err_register);
    *tensor_buffer_handle = reinterpret_cast<LiteRtTensorBufferHandle>(handle);
    return kLiteRtStatusOk;
err_register:
    return kLiteRtStatusErrorRuntimeFailure;
}

static LiteRtStatus bstorm_LiteRt_unregister_tensor_buffer(LiteRtDispatchDeviceContext device_context,
                                    LiteRtTensorBufferHandle handle)
{
    bstorm_result rc = BSTORM_RESULT_INITIALIZER();
    void* buffer_handle = reinterpret_cast<void*>(handle);
    B_STORM_CHECKED_CALL(rc, device_context->unregister_buffer, (buffer_handle), err_unregister);
    return kLiteRtStatusOk;
err_unregister:
    return kLiteRtStatusErrorRuntimeFailure;
}

static LiteRtStatus bstorm_LiteRt_invocation_context_create(
    const LiteRtRuntimeContext* runtime_context,
    LiteRtDispatchDeviceContext device_context,
    LiteRtDispatchExecutableType exec_type,
    const LiteRtMemBuffer* mem_buffer, const char* function_name,
    int num_inputs, int num_outputs,
    LiteRtDispatchInvocationContext* invocation_context)
{
    bstorm_result rc = BSTORM_RESULT_INITIALIZER();
    if (num_inputs < 0 || num_outputs < 0) {
        return kLiteRtStatusErrorInvalidArgument;
    }
    *invocation_context = new LiteRtDispatchInvocationContextT();
    B_STORM_CHECKED_CALL(rc, (*invocation_context)->init, (
        device_context, exec_type, mem_buffer, function_name,
        num_inputs, num_outputs), err_init);
    return kLiteRtStatusOk;
err_init:
    delete *invocation_context;
    return kLiteRtStatusErrorRuntimeFailure;
}

static LiteRtStatus bstorm_LiteRt_invocation_context_destroy(
    LiteRtDispatchInvocationContext invocation_context)
{
    delete invocation_context;
    return kLiteRtStatusOk;
}

